    string findShortestWay(vector<vector<int>>& maze, vector<int>& ball,
                           vector<int>& hole) {

        int n = maze.size(), m = maze[0].size();
        vector<vector<pair<int, string>>> dp(
            n, vector<pair<int, string>>(m, {INT_MAX, ""}));
        vector<pair<int, int>> dirs = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
        vector<char> dirChar = {'u', 'd', 'l', 'r'};

        queue<cell> q;
        q.push(cell(ball[0], ball[1], ""));
        dp[ball[0]][ball[1]] = {0, ""};

        while (!q.empty()) {
            auto [r, c, str] = q.front();
            q.pop();

            for (int i = 0; i < 4; i++) {
                int nr = r + dirs[i].first, nc = c + dirs[i].second, steps = 0;
                while (nr >= 0 && nc >= 0 && nr < n && nc < m &&
                       maze[nr][nc] == 0) {
                    steps++;
                    if (nr == hole[0] && nc == hole[1]) {
                        nr += dirs[i].first, nc += dirs[i].second;
                        break;
                    }
                    nr += dirs[i].first, nc += dirs[i].second;
                }
                nr -= dirs[i].first, nc -= dirs[i].second;
                if (dp[nr][nc].first > dp[r][c].first + steps) {
                    dp[nr][nc] = {dp[r][c].first + steps, str + dirChar[i]};
                    q.push(cell(nr, nc, str + dirChar[i]));
                } else if (dp[nr][nc].first == dp[r][c].first + steps) {
                    dp[nr][nc].second =
                        min(dp[nr][nc].second, str + dirChar[i]);
                }
            }
        }
        return dp[hole[0]][hole[1]].first == INT_MAX
                   ? "impossible"
                   : dp[hole[0]][hole[1]].second;
    }


